#!/bin/bash
# Run all benchmarks
set -euo pipefail

BENCH_DIR="$(dirname "$0")"
LOG_FILE="$BENCH_DIR/$(date '+%Y-%m-%d-%H-%M').log"
exec > >(tee "$LOG_FILE") 2>&1

# Encode a natural number n as a ternary tree (binary encoding, matching JS of_nat)
# Produces: fork(LSB, fork(next_bit, ... fork(MSB, leaf)...))
# where 0-bit -> fork(leaf, ...) and 1-bit -> fork(stem(leaf), ...)
encode_nat() {
  local n=$1 result="0" i bits=()
  while [ "$n" -gt 0 ]; do
    bits+=( $((n & 1)) )
    n=$((n >> 1))
  done
  for (( i=${#bits[@]}-1; i>=0; i-- )); do
    if [ "${bits[$i]}" -eq 1 ]; then
      result="210${result}"
    else
      result="20${result}"
    fi
  done
  printf '%s' "$result"
}

# Build a fork-encoded list [start, start+step, ..., end] (cons h t = "2" h t, nil = "0")
# Elements are encoded as natural numbers.  Build by prepending from the far end.
make_nat_list() {
  local start=$1 stop=$2 step=$3 result="0" k
  for (( k=stop; k!=start-step; k-=step )); do
    result="2$(encode_nat "$k")${result}"
  done
  printf '%s' "$result"
}

# --- System info ---
_cpu() {
  if [[ "$(uname)" == "Darwin" ]]; then
    sysctl -n machdep.cpu.brand_string 2>/dev/null || echo "unknown"
  elif [[ -f /proc/cpuinfo ]]; then
    grep "model name" /proc/cpuinfo | head -1 | cut -d: -f2 | xargs
  else
    echo "unknown"
  fi
}
_cores() {
  if [[ "$(uname)" == "Darwin" ]]; then
    sysctl -n hw.logicalcpu
  else
    nproc 2>/dev/null || echo "?"
  fi
}

printf "cpu:   %s (%s, %s cores)\n" "$(_cpu)" "$(uname -m)" "$(_cores)"
printf "os:    %s\n" "$(uname -sr)"
printf "date:  %s\n" "$(date '+%Y-%m-%d %H:%M')"
echo

# --- sanity-check (size size) ---
SIZE_TERNARY='21212120112121100101020212021201120112002121200121100212120212021200010212021200011202120212000101120101121201121211001010200'
SIZE_EXPECTED='111111111111111111111111111111111111111111111111111111111111111111111111111111111111111111111111111111111111111111111111111110'

echo "sanity-check (size size)"
"$BENCH_DIR/run-one.sh" "$SIZE_EXPECTED" "$SIZE_TERNARY" "$SIZE_TERNARY" ||:
echo

# --- recursive-fib (n=24) ---
FIB_N=24  # Chosen so reduction dominates parsing (tune as needed)
FIB_N_TERNARY=$(encode_nat "$FIB_N")
FIB_TERNARY=''
FIB_EXPECTED=$(encode_nat 75025)  # fib(24), where fib(0)=1,fib(1)=1,...

echo "recursive-fib (n=$FIB_N)"
"$BENCH_DIR/run-one.sh" "$FIB_EXPECTED" "$FIB_TERNARY" "$FIB_N_TERNARY" ||:
echo

# --- silly-exp (n=8) ---
# silly_exp computes 2^2^n; n=8 -> 2^256 (tune n up if slowest impl finishes quickly)
SILLY_EXP_N=16
SILLY_EXP_N_TERNARY=$(encode_nat "$SILLY_EXP_N")
SILLY_EXP_TERNARY=''
SILLY_EXP_EXPECTED=$(encode_nat 65536)  # 2^16 = 65536

echo "silly-exp (n=$SILLY_EXP_N)"
"$BENCH_DIR/run-one.sh" "$SILLY_EXP_EXPECTED" "$SILLY_EXP_TERNARY" "$SILLY_EXP_N_TERNARY" ||:
echo

# --- merge-sort (n=2000, descending input) ---
MERGE_SORT_N=2000
MERGE_SORT_TERNARY=''
# Input: descending [N, N-1, ..., 1].  Expected: ascending [1, 2, ..., N].
# make_nat_list(start=N, stop=1, step=-1) prepends from stop upward -> [N,...,1]
# make_nat_list(start=1, stop=N, step=1)  prepends from N downward  -> [1,...,N]
MERGE_SORT_INPUT=$(make_nat_list "$MERGE_SORT_N" 1 -1)
MERGE_SORT_EXPECTED=$(make_nat_list 1 "$MERGE_SORT_N" 1)

echo "merge-sort (n=$MERGE_SORT_N, descending)"
"$BENCH_DIR/run-one.sh" "$MERGE_SORT_EXPECTED" "$MERGE_SORT_TERNARY" "$MERGE_SORT_INPUT" ||:
